prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?normId ?origId WHERE {
  ?model a bboExt:Model .
  ?model bbo:name ?modelName .
  OPTIONAL { ?model tai:normalizedId ?normId . }
  OPTIONAL { ?model tai:originalId ?origId . }
  FILTER(CONTAINS(STR(?normId), "4ccc3fd7") OR CONTAINS(STR(?origId), "4ccc3fd7"))
}
LIMIT 10

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?normId ?origId WHERE {
  ?model a bboExt:Model .
  ?model bbo:name ?modelName .
  OPTIONAL { ?model tai:normalizedId ?normId . }
  OPTIONAL { ?model tai:originalId ?origId . }
  FILTER(STR(?normId) = "4ccc3fd711004f519782ac92e58f6ddd" || STR(?origId) = "4ccc3fd711004f519782ac92e58f6ddd")
}
LIMIT 10

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?choreo ?choreoName ?task ?taskName ?part ?partName ?gate ?gateName ?start ?startName ?end ?endName WHERE {
  ?model a bboExt:Model .
  ?model tai:originalId "4ccc3fd711004f519782ac92e58f6ddd" .
  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography .
  ?choreo tai:belongsTo ?defs .
  OPTIONAL { ?choreo bbo:name ?choreoName . }

  OPTIONAL {
    ?task a bboExt:ChoreographyTask .
    ?task tai:belongsTo ?choreo .
    OPTIONAL { ?task bbo:name ?taskName . }
  }

  OPTIONAL {
    ?part a bboExt:Participant .
    ?part tai:belongsTo ?choreo .
    OPTIONAL { ?part bbo:name ?partName . }
  }

  OPTIONAL {
    ?gate a bboExt:ExclusiveGateway .
    ?gate tai:belongsTo ?choreo .
    OPTIONAL { ?gate bbo:name ?gateName . }
  }

  OPTIONAL {
    ?start a bboExt:StartEvent .
    ?start tai:belongsTo ?choreo .
    OPTIONAL { ?start bbo:name ?startName . }
  }

  OPTIONAL {
    ?end a bboExt:EndEvent .
    ?end tai:belongsTo ?choreo .
    OPTIONAL { ?end bbo:name ?endName . }
  }
}
LIMIT 50
